def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start, end = nums[0], nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start != end:
                result.append(f"{start}-{end}")
            else:
                result.append(str(start))
            start = end = num

    if start != end:
        result.append(f"{start}-{end}")
    else:
        result.append(str(start))

    return ', '.join(result)
